import{_ as e,o as d,c as a,a0 as o}from"./chunks/framework.7S7UUFQz.js";const p=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md"}'),s={name:"benchmarks.md"};function i(r,t,n,l,c,h){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks&quot;">​</a></h1><p>Benchmark fixtures are generated at runtime with deterministic rectangular polygon grids. No H3 grid or hexagonal resolution system is used.</p><h2 id="sprint-2-3-targets" tabindex="-1">Sprint 2-3 Targets <a class="header-anchor" href="#sprint-2-3-targets" aria-label="Permalink to &quot;Sprint 2-3 Targets&quot;">​</a></h2><ul><li><code>getZoneById</code>: constant-time map lookup.</li><li><code>latLngToZone</code>: indexed lookup path must be measured on 10K polygons before Sprint 3 is marked complete.</li><li><code>getZonesInBounds</code>: viewport-sized bbox query must use the spatial index in production.</li><li>Dataset load: benchmark smoke must include index construction time before release candidate hardening.</li><li>Memory: use <code>pnpm bench:memory</code> after a build to record heap deltas for deterministic large graph fixtures.</li></ul><p>Run:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span></span></code></pre></div><p>The first tracked fixture is 10K polygons (<code>100 x 100</code>). A 100K polygon fixture exists for larger smoke runs, but it should not be committed as static data.</p><h2 id="latest-smoke-run" tabindex="-1">Latest Smoke Run <a class="header-anchor" href="#latest-smoke-run" aria-label="Permalink to &quot;Latest Smoke Run&quot;">​</a></h2><p>Recorded on 2026-07-14 with <code>pnpm bench</code>:</p><table tabindex="0"><thead><tr><th>Benchmark</th><th style="text-align:right;">Mean</th><th style="text-align:right;">p99</th><th style="text-align:right;">p995</th></tr></thead><tbody><tr><td><code>latLngToZone</code>, 10K polygons</td><td style="text-align:right;"><code>0.0003 ms</code></td><td style="text-align:right;"><code>0.0007 ms</code></td><td style="text-align:right;"><code>0.0009 ms</code></td></tr><tr><td><code>getZonesInBounds</code>, 10K polygons</td><td style="text-align:right;"><code>0.0650 ms</code></td><td style="text-align:right;"><code>0.1762 ms</code></td><td style="text-align:right;"><code>0.2130 ms</code></td></tr><tr><td><code>getZoneById</code>, 10K polygons</td><td style="text-align:right;"><code>0.0000 ms</code></td><td style="text-align:right;"><code>0.0000 ms</code></td><td style="text-align:right;"><code>0.0001 ms</code></td></tr><tr><td>Engine construction, 10K polygons</td><td style="text-align:right;"><code>9.8093 ms</code></td><td style="text-align:right;"><code>23.2468 ms</code></td><td style="text-align:right;"><code>23.2468 ms</code></td></tr><tr><td>Dataset validation load, 10K polygons</td><td style="text-align:right;"><code>7.8898 ms</code></td><td style="text-align:right;"><code>15.1426 ms</code></td><td style="text-align:right;"><code>15.1426 ms</code></td></tr><tr><td><code>latLngToZone</code>, 100K polygons</td><td style="text-align:right;"><code>0.0004 ms</code></td><td style="text-align:right;"><code>0.0005 ms</code></td><td style="text-align:right;"><code>0.0006 ms</code></td></tr></tbody></table><p>Vitest reports p99/p995 instead of p95. Since p99 is below the p95 target, the p95 gate is treated as satisfied for this smoke run.</p><h2 id="latest-memory-run" tabindex="-1">Latest Memory Run <a class="header-anchor" href="#latest-memory-run" aria-label="Permalink to &quot;Latest Memory Run&quot;">​</a></h2><p>Recorded on 2026-07-14 with <code>pnpm bench:memory</code>:</p><table tabindex="0"><thead><tr><th>Fixture</th><th style="text-align:right;">Features</th><th style="text-align:right;">Dataset heap delta</th><th style="text-align:right;">Engine heap delta</th><th style="text-align:right;">Total heap delta</th></tr></thead><tbody><tr><td><code>100x100</code> synthetic grid</td><td style="text-align:right;"><code>10,000</code></td><td style="text-align:right;"><code>11,060,496 bytes</code></td><td style="text-align:right;"><code>11,399,240 bytes</code></td><td style="text-align:right;"><code>22,459,736 bytes</code></td></tr></tbody></table><p>The memory benchmark uses <code>node --expose-gc</code> and records heap deltas after deterministic fixture creation and engine index construction. It is kept separate from <code>pnpm bench</code> so the regular benchmark smoke stays quick.</p>',15)])])}const m=e(s,[["render",i]]);export{p as __pageData,m as default};
